from __future__ import annotations

import base64
import logging
import ssl
import typing

from .._backends.base import SOCKET_OPTION, NetworkBackend
from .._exceptions import ProxyError
from .._models import (
    URL,
    Origin,
    Request,
    Response,
    enforce_bytes,
    enforce_headers,
    enforce_url,
)
from .._ssl import default_ssl_context
from .._synchronization import Lock
from .._trace import Trace
from .connection import HTTPConnection
from .connection_pool import ConnectionPool
from .http11 import HTTP11Connection
from .interfaces import ConnectionInterface

ByteOrStr = typing.Union[bytes, str]
HeadersAsSequence = typing.Sequence[typing.Tuple[ByteOrStr, ByteOrStr]]
HeadersAsMapping = typing.Mapping[ByteOrStr, ByteOrStr]


logger = logging.getLogger("httpcore.proxy")


def merge_headers(
    default_headers: typing.Sequence[tuple[bytes, bytes]] | None = None,
    override_headers: typing.Sequence[tuple[bytes, bytes]] | None = None,
) -> list[tuple[bytes, bytes]]:
    """
    Append default_headers and override_headers, de-duplicating if a key exists
    in both cases.
    """
    default_headers = [] if default_headers is None else list(default_headers)
    override_headers = [] if override_headers is None else list(override_headers)
    has_override = set(key.lower() for key, value in override_headers)
    default_headers = [
        (key, value)
        for key, value in default_headers
        if key.lower() not in has_override
    ]
    return default_headers + override_headers


class HTTPProxy(ConnectionPool):  # pragma: nocover
    """
    A connection pool that sends requests via an HTTP proxy.
    """

    def __init__(
        self,
        proxy_url: URL | bytes | str,
        proxy_auth: tuple[bytes | str, bytes | str] | None = None,
        proxy_headers: HeadersAsMapping | HeadersAsSequence | None = None,
        ssl_context: ssl.SSLContext | None = None,
        proxy_ssl_context: ssl.SSLContext | None = None,
        max_connections: int | None = 10,
        max_keepalive_connections: int | None = None,
        keepalive_expiry: float | None = None,
        http1: bool = True,
        http2: bool = False,
        retries: int = 0,
        local_address: str | None = None,
        uds: str | None = None,
        network_backend: NetworkBackend | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> None:
        """
        Initialize an HTTPProxy connection pool.

        Parameters:
            proxy_url: The URL to use when connecting to the proxy server.
            proxy_auth: Optional proxy authentication (username, password).
            proxy_headers: Optional headers to send to the proxy.
            ssl_context: SSL context for remote origins.
            proxy_ssl_context: SSL context for the proxy server.
            max_connections: Maximum concurrent connections allowed.
            max_keepalive_connections: Maximum idle connections to keep.
            keepalive_expiry: Idle connection expiry in seconds.
            http1: Support HTTP/1.1.
            http2: Support HTTP/2.
            retries: Number of connection retries.
            local_address: Local address to bind to for outgoing connections.
            uds: Unix Domain Socket to use for connections.
            network_backend: Backend used for network I/O.
            socket_options: Iterable of socket options.
        """
        super().__init__(
            max_connections=max_connections,
            max_keepalive_connections=max_keepalive_connections,
            keepalive_expiry=keepalive_expiry,
            http1=http1,
            http2=http2,
            retries=retries,
            local_address=local_address,
            uds=uds,
            network_backend=network_backend,
            socket_options=socket_options,
        )

        self.proxy_url = enforce_url(proxy_url)
        self.proxy_auth = proxy_auth
        # Normalize proxy headers into a sequence of bytes pairs
        if proxy_headers is None:
            self.proxy_headers = []
        elif isinstance(proxy_headers, dict):
            self.proxy_headers = [
                (enforce_bytes(k), enforce_bytes(v))
                for k, v in proxy_headers.items()
            ]
        else:
            self.proxy_headers = [
                (enforce_bytes(k), enforce_bytes(v)) for k, v in proxy_headers
            ]

        # Use default SSL contexts if not provided.
        self.ssl_context = ssl_context or default_ssl_context()
        self.proxy_ssl_context = proxy_ssl_context or self.ssl_context

        # Precompute proxy-authorization header if proxy_auth provided.
        if proxy_auth is not None:
            username, password = proxy_auth
            username_b = enforce_bytes(username)
            password_b = enforce_bytes(password)
            credentials = base64.b64encode(b"%b:%b" % (username_b, password_b))
            self._proxy_auth_header = (
                b"proxy-authorization",
                b"Basic " + credentials,
            )
        else:
            self._proxy_auth_header = None

        # Lock for serializing connection setup if needed.
        self._network_lock = Lock()

    def create_connection(self, origin: Origin, timeout: float | None = None) -> ConnectionInterface:
        """
        Create a new connection to be used for requests to the given origin.

        The returned connection will handle communicating via the configured HTTP proxy.
        """
        # For HTTP connections we can send requests directly via the proxy.
        # For HTTPS origins we need to establish a CONNECT tunnel and then
        # perform TLS to the origin. This simplified implementation will
        # always wrap an HTTP11Connection as a proxy connection wrapper.
        return ProxyHTTP11Connection(
            proxy_url=self.proxy_url,
            proxy_headers=self.proxy_headers,
            proxy_auth_header=self._proxy_auth_header,
            origin=origin,
            ssl_context=self.ssl_context,
            proxy_ssl_context=self.proxy_ssl_context,
            network_backend=self._network_backend,
            timeout=timeout,
        )


class ProxyHTTP11Connection(ConnectionInterface):
    """
    A connection that forwards HTTP/1.1 requests via an HTTP proxy.

    This class wraps a lower-level HTTP11Connection and is responsible for
    performing the proxy CONNECT when necessary, and for adding proxy-specific
    request headers.
    """

    def __init__(
        self,
        proxy_url: URL,
        proxy_headers: list[tuple[bytes, bytes]] | None,
        proxy_auth_header: tuple[bytes, bytes] | None,
        origin: Origin,
        ssl_context: ssl.SSLContext,
        proxy_ssl_context: ssl.SSLContext,
        network_backend: NetworkBackend | None,
        timeout: float | None = None,
    ) -> None:
        """
        Initialize a ProxyHTTP11Connection.

        Parameters:
            proxy_url: The proxy server URL.
            proxy_headers: Default headers to include in proxy requests.
            proxy_auth_header: Precomputed Proxy-Authorization header (bytes pair).
            origin: The remote origin that requests will target.
            ssl_context: SSL context for the remote origin.
            proxy_ssl_context: SSL context for the proxy server.
            network_backend: Backend for network operations.
            timeout: Optional default timeout for connection operations.
        """
        self.proxy_url = proxy_url
        self.proxy_headers = proxy_headers or []
        self.proxy_auth_header = proxy_auth_header
        self.origin = origin
        self.ssl_context = ssl_context
        self.proxy_ssl_context = proxy_ssl_context
        self._network_backend = network_backend
        self.timeout = timeout

        # Underlying connection to the proxy server.
        self._http11 = HTTP11Connection(
            origin=Origin(scheme=proxy_url.scheme, host=proxy_url.host, port=proxy_url.port or 80),
            http2=False,
            ssl_context=self.proxy_ssl_context,
            network_backend=self._network_backend,
        )

        self._closed = False
        self._idle = False

    def handle_request(
        self,
        request: Request,
        timeout: float | None = None,
        trace: Trace | None = None,
    ) -> Response:
        """
        Send a request through the proxy to the target origin and return a response.

        This method handles adding necessary proxy headers, performing CONNECT
        for TLS origins, and delegating to the underlying HTTP/1.1 connection.
        """
        if self._closed:
            raise RuntimeError("Connection is closed")

        # Merge proxy headers and request headers, ensuring bytes types.
        request_headers = enforce_headers(request.headers)
        proxy_headers = list(self.proxy_headers)
        if self.proxy_auth_header is not None and b"proxy-authorization" not in {
            k.lower() for k, _ in proxy_headers
        }:
            proxy_headers.append(self.proxy_auth_header)

        # For TLS origins, perform CONNECT before sending the actual request.
        if self.origin.scheme == "https":
            connect_host = f"{self.origin.host}:{self.origin.port}"
            # Build CONNECT request (simplified representation).
            connect_headers = [(b"host", enforce_bytes(connect_host))]
            connect_headers = merge_headers(connect_headers, proxy_headers)
            # Execute a CONNECT via the underlying HTTP/1.1 connection.
            connect_req = Request(method=b"CONNECT", url=URL(f"{self.proxy_url.raw}{connect_host}"), headers=connect_headers, stream=None)
            response = self._http11.handle_request(connect_req, timeout=timeout, trace=trace)
            if response.status != 200:
                raise ProxyError(f"Proxy CONNECT failed with status {response.status}")
            # After successful CONNECT, we would upgrade the underlying socket to TLS
            # and wrap it for the target origin. For this simplified implementation
            # we assume HTTP11Connection can be reused for the tunneled connection.
            # In a full implementation, we'd perform SSL handshake here.

        # For non-TLS origins, or after CONNECT, forward the request via the proxy.
        # When sending via a proxy, the request-target should be the full URL.
        forwarded_request = Request(
            method=request.method,
            url=request.url if self.origin.scheme == "http" else request.url,
            headers=merge_headers(proxy_headers, request_headers),
            stream=request.stream,
        )
        response = self._http11.handle_request(forwarded_request, timeout=timeout, trace=trace)
        # Keep track of idle state based on response/connection.
        self._idle = True
        return response

    def can_handle_request(self, request: Request) -> bool:
        """
        Determine if this connection is suitable for handling the given request.

        Returns True if the connection's origin and state match the request target.
        """
        # This simplified implementation assumes the connection can handle requests
        # for the same origin (scheme/host/port).
        return (
            request.url.scheme == self.origin.scheme
            and request.url.host == self.origin.host
            and (request.url.port or (443 if request.url.scheme == "https" else 80))
            == (self.origin.port or (443 if self.origin.scheme == "https" else 80))
            and not self._closed
        )

    def close(self) -> None:
        """
        Close the connection and release any underlying resources.
        """
        if not self._closed:
            try:
                self._http11.close()
            finally:
                self._closed = True

    def info(self) -> dict:
        """
        Return diagnostic information about the connection.
        """
        return {
            "proxy_url": str(self.proxy_url),
            "origin": f"{self.origin.scheme}://{self.origin.host}:{self.origin.port}",
            "closed": self._closed,
            "idle": self._idle,
        }

    def is_available(self) -> bool:
        """
        Return True if the connection is available for reuse.
        """
        return not self._closed and self._idle

    def has_expired(self) -> bool:
        """
        Return True if the connection should be discarded due to expiry.
        """
        # This simplified implementation doesn't track expiry separately.
        return self._closed

    def is_idle(self) -> bool:
        """
        Return True if the connection is currently idle.
        """
        return self._idle

    def is_closed(self) -> bool:
        """
        Return True if the connection has been closed.
        """
        return self._closed

    def __repr__(self) -> str:
        """
        Return a representation of the connection for debugging.
        """
        return (
            f"<ProxyHTTP11Connection proxy={self.proxy_url.raw!r} "
            f"origin={self.origin!r} closed={self._closed}>"
        )